# scripts/risk_score.py
# Adjusts CVSS scores with context multipliers for this system

from dataclasses import dataclass
from typing import Literal

@dataclass
class Vulnerability:
    id: str
    package: str
    version: str
    cvss_base: float

@dataclass
class ContextProfile:
    """System-level context that adjusts the raw CVSS score."""
    internet_facing: bool  # adds 1.5 if True
    has_pii_access: bool   # adds 1.0 if True
    no_mitigating_control: bool  # adds 0.5 if True

    def multiplier(self) -> float:
        delta = 0.0
        if self.internet_facing:
            delta += 1.5
        if self.has_pii_access:
            delta += 1.0
        if self.no_mitigating_control:
            delta += 0.5
        return delta

def adjusted_score(vuln: Vulnerability, ctx: ContextProfile) -> float:
    return min(10.0, vuln.cvss_base + ctx.multiplier())

def priority(
    score: float,
) -> Literal["P0", "P1", "P2", "P3"]:
    if score >= 9.0:
        return "P0"  # RTO: 4 hours
    elif score >= 7.0:
        return "P1"  # RTO: 24 hours
    elif score >= 4.0:
        return "P2"  # RTO: 7 days
    return "P3"      # RTO: 30 days


# Example usage:
CONTEXT = ContextProfile(
    internet_facing=True,
    has_pii_access=True,
    no_mitigating_control=False,
)

vuln = Vulnerability(
    id="CVE-2024-XXXX",
    package="cryptography",
    version="41.0.0",
    cvss_base=7.5,
)

score = adjusted_score(vuln, CONTEXT)
print(f"{vuln.id}: base={vuln.cvss_base} adjusted={score:.1f} priority={priority(score)}")
